Here is the JavaScript code to calculate the factorial of x where x is 7.
function factorial(x) {
  if (x === 0) return 1;
  return x * factorial(x - 1);
}
const x = 7;
const result = factorial(x);
console.log("The factorial of " + x + " is " + result);
